import Swiper from 'swiper/bundle';
import 'swiper/css/bundle';

const LG_BREAKPOINT = 992;
const MD_BREAKPOINT = 768;
const SM_BREAKPOINT = 576;

// большой слайдер в хэдере
new Swiper('.header-features-large-slider', {
    loop: true,
    autoplay: {
        delay: 10000,
        disableOnInteraction: false
    },
    noSwiping: true,
    noSwipingClass: 'swiper-slide',
});

// секция с бегущей строкой
new Swiper('.currencies-running-line-slider', {
    loop: true,
    freeMode: true,
    slidesPerView: 'auto',
    speed: 10000,
    autoplay: {
        delay: 0,
        disableOnInteraction: false
    },
    noSwiping: true,
    noSwipingClass: 'swiper-slide',
});

if (window.screen.width <= LG_BREAKPOINT) {
    const defaultSliderSettings = {
        slidesPerView: 1.3,
        spaceBetween: 20,
        breakpoints: {
            [SM_BREAKPOINT + 1]: {
                slidesPerView: 1.6
            },
            [MD_BREAKPOINT + 1]: {
                slidesPerView: 2.3
            }
        }
    }

    // мы знаем как вам заработать на форекс
    new Swiper('.analytics-news-section-slider', defaultSliderSettings);

    // начать торговать легко
    new Swiper('.get-started-tutorial-slider', {
        ...defaultSliderSettings
    });

    // курсы на рынке форекс
    new Swiper('.currencies-brief-news-section-slider', defaultSliderSettings);
}